module traffic_light(
    input rst_n, input clk, input pass_request,
    output [7:0] clock,
    output reg red, yellow, green
);
localparam IDLE = 2'b00, S1_RED = 2'b01, S2_YELLOW = 2'b10, S3_GREEN = 2'b11;
reg [1:0] state;
reg [7:0] cnt;
reg p_red, p_yellow, p_green;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
        cnt <= 8'd0;
        red <= 1'b0;
        yellow <= 1'b0;
        green <= 1'b0;
    end
    else begin
        case (state)
            IDLE: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b0;
                p_red <= 1'b0;
                p_yellow <= 1'b0;
                p_green <= 1'b0;
                state <= S1_RED;
            end
            S1_RED: begin
                red <= 1'b1;
                yellow <= 1'b0;
                green <= 1'b0;
                p_red <= 1'b1;
                p_yellow <= 1'b0;
                p_green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= S2_YELLOW;
                    cnt <= 8'd0;
                end
            end
            S2_YELLOW: begin
                red <= 1'b0;
                yellow <= 1'b1;
                green <= 1'b0;
                p_red <= 1'b0;
                p_yellow <= 1'b1;
                p_green <= 1'b0;
                if (cnt == 8'd3) begin
                    state <= S3_GREEN;
                    cnt <= 8'd0;
                end
            end
            S3_GREEN: begin
                red <= 1'b0;
                yellow <= 1'b0;
                green <= 1'b1;
                p_red <= 1'b0;
                p_yellow <= 1'b0;
                p_green <= 1'b1;
                if (cnt == 8'd3) begin
                    state <= S1_RED;
                    cnt <= 8'd0;
                end
            end
    endcase
end
end // Auto-repaired
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 8'd0;
    end
    else begin
        if (cnt == 8'd0) begin
            cnt <= (state == S1_RED) ? 8'd3 : 8'd10;
        end
        else begin
            cnt <= cnt - 1'b1;
        end
    end
end
assign clock = cnt;
endmodule
